"<section class='card' style='margin-top:14px'><h3 id='raw_title'></h3><div id='raw_subtitle' class='muted'></div><textarea id='raw_cfg' readonly></textarea></section>"
"<script>"
"const ALLOWED_GPIOS=[0,1,3,4,5,6,7,10];"
"const OUTPUT_TYPES=['relay','pwm','ws2812'];"
"const INPUT_ROLES=['generic_binary','motion','presence','contact','limit'];"
"const PULLS=['up','down','none'];"
"const SENSOR_TYPES=['ds18b20_bus','aht20','sht3x','bme280'];"
"const BUTTON_ACTIONS=['none','master_toggle','master_on','master_off','toggle_output','set_output','dim_step_up','dim_step_down'];"
"const BOARD_PROFILES=['esp32-c3-supermini','esp32-c3-luatos','esp32-c3-devkitm-1'];"
"const I18N={ru:{title:'ESP32-C3 MQTT',subtitle:'MQTT-конфигуратор для ESP32-C3: русский/английский интерфейс, объединённые входы и кнопки, акцент на ESP32-C3 Super Mini.',scan_wifi:'Сканировать Wi-Fi',save_apply:'Сохранить и применить',apply_only:'Применить без сохранения',factory_reset:'Сброс к заводским',connectivity:'Подключение',device_name:'Имя устройства',hostname:'Hostname',ap_ssid:'SSID точки доступа',ap_pass:'Пароль точки доступа',wifi_scan:'Список Wi-Fi',sta_ssid:'SSID клиента',sta_pass:'Пароль клиента',mqtt_host:'MQTT хост',mqtt_port:'MQTT порт',mqtt_user:'MQTT пользователь',mqtt_pass:'MQTT пароль',topic_prefix:'Префикс топиков',client_id:'Client ID',discovery_prefix:'Префикс discovery',board_profile:'Профиль платы',mqtt_enabled:'MQTT включён',ha_discovery:'HA discovery',retain:'Retain',gpio_policy:'Политика GPIO',runtime_status:'Состояние runtime',outputs:'Выходы',add_output:'Добавить выход',io_title:'Входы и кнопки',add_io:'Добавить I/O',sensors:'Датчики',add_sensor:'Добавить датчик',raw_title:'Сырые настройки',raw_subtitle:'Нормализованный JSON, который будет сохранён в устройстве.',remove:'Удалить',id:'ID',name:'Имя',kind:'Тип I/O',kind_input:'Вход',kind_button:'Кнопка',type:'Тип',gpio:'GPIO',enabled:'Включено',active_level:'Активный уровень',default_on:'Включать по умолчанию',freq_hz:'Частота, Гц',default_level:'Уровень по умолчанию',inverted:'Инверсия',pixels:'Количество пикселей',color_order:'Порядок цветов',role:'Назначение',pull:'Подтяжка',long_press_ms:'Долгое нажатие, мс',short_action:'Короткое действие',short_target:'Цель короткого',short_value:'Шаг/значение',long_action:'Долгое действие',long_target:'Цель долгого',long_value:'Шаг/значение',poll_sec:'Период опроса, сек',sda:'SDA',scl:'SCL',address:'Адрес',select_network:'Выберите сеть...',found_networks:'Найдено сетей: {count}',found_networks_cached:'Показан кэш сканирования: {count}',msg_saved:'Конфигурация сохранена',msg_apply:'Применение запланировано',msg_saved_apply:'Сохранение и применение запланированы',msg_reset:'Сброс к заводским запланирован',confirm_reset:'Стереть всю конфигурацию устройства и перезагрузить?',no_gpio_conflicts:'Конфликтов GPIO не найдено.',conflicts:'Конфликты',empty_io:'Пока нет входов или кнопок.',mode:'режим',mqtt_state:'mqtt',ap_state:'ap',connected:'подключён',offline:'офлайн',output_name:'Выход',io_name:'Вход',button_name:'Кнопка',sensor_name:'Датчик'},en:{title:'ESP32-C3 MQTT',subtitle:'MQTT configurator for ESP32-C3 with bilingual UI, unified inputs/buttons editor, and a focus on ESP32-C3 Super Mini.',scan_wifi:'Scan Wi-Fi',save_apply:'Save and apply',apply_only:'Apply only',factory_reset:'Factory reset',connectivity:'Connectivity',device_name:'Device name',hostname:'Hostname',ap_ssid:'AP SSID',ap_pass:'AP password',wifi_scan:'Wi-Fi scan',sta_ssid:'STA SSID',sta_pass:'STA password',mqtt_host:'MQTT host',mqtt_port:'MQTT port',mqtt_user:'MQTT user',mqtt_pass:'MQTT password',topic_prefix:'Topic prefix',client_id:'Client ID',discovery_prefix:'Discovery prefix',board_profile:'Board profile',mqtt_enabled:'MQTT enabled',ha_discovery:'HA discovery',retain:'Retain',gpio_policy:'GPIO policy',runtime_status:'Runtime status',outputs:'Outputs',add_output:'Add output',io_title:'Inputs and buttons',add_io:'Add I/O',sensors:'Sensors',add_sensor:'Add sensor',raw_title:'Raw config',raw_subtitle:'Normalized JSON that will be saved into the device.',remove:'Remove',id:'ID',name:'Name',kind:'I/O kind',kind_input:'Input',kind_button:'Button',type:'Type',gpio:'GPIO',enabled:'Enabled',active_level:'Active level',default_on:'Default ON',freq_hz:'Freq Hz',default_level:'Default level',inverted:'Inverted',pixels:'Pixels',color_order:'Color order',role:'Role',pull:'Pull',long_press_ms:'Long press ms',short_action:'Short action',short_target:'Short target',short_value:'Step/value',long_action:'Long action',long_target:'Long target',long_value:'Step/value',poll_sec:'Poll sec',sda:'SDA',scl:'SCL',address:'Address',select_network:'Select network...',found_networks:'Networks found: {count}',found_networks_cached:'Cached scan results: {count}',msg_saved:'Config saved',msg_apply:'Apply scheduled',msg_saved_apply:'Save + apply scheduled',msg_reset:'Factory reset scheduled',confirm_reset:'Erase full device configuration and reboot?',no_gpio_conflicts:'No GPIO conflicts detected.',conflicts:'Conflicts',empty_io:'No inputs or buttons yet.',mode:'mode',mqtt_state:'mqtt',ap_state:'ap',connected:'connected',offline:'offline',output_name:'Output',io_name:'Input',button_name:'Button',sensor_name:'Sensor'}};"
"const OUTPUT_TYPE_LABELS={relay:{ru:'Реле',en:'Relay'},pwm:{ru:'PWM',en:'PWM'},ws2812:{ru:'WS2812',en:'WS2812'}};"
"const INPUT_ROLE_LABELS={generic_binary:{ru:'Общий вход',en:'Generic binary'},motion:{ru:'Движение',en:'Motion'},presence:{ru:'Присутствие',en:'Presence'},contact:{ru:'Контакт',en:'Contact'},limit:{ru:'Концевик',en:'Limit'}};"
"const SENSOR_TYPE_LABELS={ds18b20_bus:{ru:'DS18B20 шина',en:'DS18B20 bus'},aht20:{ru:'AHT20',en:'AHT20'},sht3x:{ru:'SHT3X',en:'SHT3X'},bme280:{ru:'BME280',en:'BME280'}};"
"const BUTTON_ACTION_LABELS={none:{ru:'Нет',en:'None'},master_toggle:{ru:'Переключить всё',en:'Toggle all'},master_on:{ru:'Включить всё',en:'All ON'},master_off:{ru:'Выключить всё',en:'All OFF'},toggle_output:{ru:'Переключить выход',en:'Toggle output'},set_output:{ru:'Установить выход',en:'Set output'},dim_step_up:{ru:'Яркость +',en:'Brightness up'},dim_step_down:{ru:'Яркость -',en:'Brightness down'}};"
"const PULL_LABELS={up:{ru:'Вверх',en:'Up'},down:{ru:'Вниз',en:'Down'},none:{ru:'Без подтяжки',en:'None'}};"
"const BOARD_PROFILE_LABELS={'esp32-c3-supermini':{ru:'ESP32-C3 Super Mini',en:'ESP32-C3 Super Mini'},'esp32-c3-luatos':{ru:'ESP32-C3 LuatOS',en:'ESP32-C3 LuatOS'},'esp32-c3-devkitm-1':{ru:'ESP32-C3 DevKitM-1',en:'ESP32-C3 DevKitM-1'}};"
"const BOARD_HINTS={'esp32-c3-supermini':{ru:'Рекомендуемый профиль по умолчанию. В этой прошивке безопасный пул GPIO уже ограничен под типовой ESP32-C3 проект.',en:'Recommended default profile. This firmware already limits GPIO selection to a safe ESP32-C3 subset.'},'esp32-c3-luatos':{ru:'Профиль для ваших LuatOS-плат. Если разводка проекта отличается, всё равно ориентируйтесь на фактические GPIO устройства.',en:'Profile for your LuatOS boards. If your hardware wiring differs, use the actual GPIO mapping of the device.'},'esp32-c3-devkitm-1':{ru:'Совместимый профиль для классической devkit-платы. Можно использовать как запасной шаблон.',en:'Compatible profile for the classic devkit board. Useful as a fallback template.'}};"
"let cfg=null;let lang=localStorage.getItem('ui_lang')||'ru';"
"function esc(v){return String(v==null?'':v).replace(/[&<>\\\"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','\\\"':'&quot;',\\\"'\\\":'&#39;'}[m]));}"
"function pick(v,d){return v===undefined||v===null?d:v;}"
"function t(k){return(I18N[lang]&&I18N[lang][k])||(I18N.en&&I18N.en[k])||k;}"
"function fmt(s,data){return String(s).replace(/\\\\{(\\\\w+)\\\\}/g,(_,k)=>data&&data[k]!==undefined?data[k]:'');}"
"function mapLabel(map,key){const v=map[key]||{};return v[lang]||v.en||v.ru||key;}"
"function setMsg(msg,ok){const el=document.getElementById('msg');el.textContent=msg||'';el.className=ok?'ok':'err';}"
"function ensure(){cfg.outputs=Array.isArray(cfg.outputs)?cfg.outputs:[];cfg.inputs=Array.isArray(cfg.inputs)?cfg.inputs:[];cfg.buttons=Array.isArray(cfg.buttons)?cfg.buttons:[];cfg.sensors=Array.isArray(cfg.sensors)?cfg.sensors:[];cfg.device=cfg.device||{};cfg.connectivity=cfg.connectivity||{};cfg.connectivity.ap=cfg.connectivity.ap||{};cfg.connectivity.sta=cfg.connectivity.sta||{};cfg.connectivity.mqtt=cfg.connectivity.mqtt||{};}"
"function gpioOptions(selected){return ALLOWED_GPIOS.map(g=>`<option value='${g}' ${Number(selected)===g?'selected':''}>GPIO${g}</option>`).join('');}"
"function enumOptions(values,selected,map){return values.map(v=>`<option value='${esc(v)}' ${String(selected)===String(v)?'selected':''}>${esc(mapLabel(map||{},v))}</option>`).join('');}"
"function boardOptions(selected){return BOARD_PROFILES.map(v=>`<option value='${esc(v)}' ${String(selected)===String(v)?'selected':''}>${esc(mapLabel(BOARD_PROFILE_LABELS,v))}</option>`).join('');}"
"function refreshRaw(){document.getElementById('raw_cfg').value=JSON.stringify(cfg,null,2);}"
"function setField(section,idx,key,value){cfg[section][idx][key]=value;render();}"
"function setNested(section,idx,parent,key,value){cfg[section][idx][parent]=cfg[section][idx][parent]||{};cfg[section][idx][parent][key]=value;render();}"
"function removeItem(section,idx){cfg[section].splice(idx,1);render();}"
"function ioEntries(){const list=[];cfg.inputs.forEach((o,i)=>list.push({section:'inputs',idx:i,kind:'input',data:o}));cfg.buttons.forEach((o,i)=>list.push({section:'buttons',idx:i,kind:'button',data:o}));return list;}"
"function inputFromButton(src){return{id:src.id||'',name:src.name||'',type:'digital',enabled:src.enabled!==false,gpio:pick(src.gpio,0),pull:pick(src.pull,'up'),inverted:!!src.inverted,role:'generic_binary'};}"
"function buttonFromInput(src){return{id:src.id||'',name:src.name||'',enabled:src.enabled!==false,gpio:pick(src.gpio,0),pull:pick(src.pull,'up'),inverted:!!src.inverted,long_press_ms:1000,actions:{short:{type:'master_toggle'},long:{type:'none'}}};}"
"function changeIoKind(section,idx,nextKind){if(section==='inputs'&&nextKind==='input')return;if(section==='buttons'&&nextKind==='button')return;const src=cfg[section][idx];cfg[section].splice(idx,1);if(nextKind==='button'){cfg.buttons.push(buttonFromInput(src));}else{cfg.inputs.push(inputFromButton(src));}render();}"
"function actionEditor(section,idx,which,a){const cur=a||{};return `<div class='row3'><div><label>${t(which+'_action')}</label><select onchange=\\\"setNested('${section}',${idx},'actions','${which}',Object.assign((((cfg['${section}'][${idx}].actions||{})['${which}'])||{}),{type:this.value}))\\\">${enumOptions(BUTTON_ACTIONS,pick(cur.type,'none'),BUTTON_ACTION_LABELS)}</select></div><div><label>${t(which+'_target')}</label><input value='${esc(pick(cur.target,''))}' oninput=\\\"setNested('${section}',${idx},'actions','${which}',Object.assign((((cfg['${section}'][${idx}].actions||{})['${which}'])||{}),{target:this.value}))\\\"/></div><div><label>${t(which+'_value')}</label><input value='${esc(cur.step!==undefined?cur.step:(cur.value!==undefined?cur.value:''))}' oninput=\\\"const obj=Object.assign((((cfg['${section}'][${idx}].actions||{})['${which}'])||{}),{});if(obj.type==='set_output'){obj.value=(this.value==='true'||this.value==='1'||this.value==='on');}else{obj.step=Number(this.value||10);}setNested('${section}',${idx},'actions','${which}',obj)\\\"/></div></div>`;}"
"function renderOutputs(){document.getElementById('outputs').innerHTML=cfg.outputs.map((o,i)=>{const type=pick(o.type,'relay');return `<div class='item'><div class='itemhead'><strong>${esc(o.name||o.id||(`${t('output_name')} ${i+1}`))}</strong><button class='danger' onclick='removeItem(\\\"outputs\\\",${i})'>${t('remove')}</button></div><div class='row'><div><label>${t('id')}</label><input value='${esc(o.id||'')}' oninput='setField(\\\"outputs\\\",${i},\\\"id\\\",this.value)'/></div><div><label>${t('name')}</label><input value='${esc(o.name||'')}' oninput='setField(\\\"outputs\\\",${i},\\\"name\\\",this.value)'/></div></div><div class='row3'><div><label>${t('type')}</label><select onchange='setField(\\\"outputs\\\",${i},\\\"type\\\",this.value)'>${enumOptions(OUTPUT_TYPES,type,OUTPUT_TYPE_LABELS)}</select></div><div><label>${t('gpio')}</label><select onchange='setField(\\\"outputs\\\",${i},\\\"gpio\\\",Number(this.value))'>${gpioOptions(pick(o.gpio,0))}</select></div><div><label><input type='checkbox' ${o.enabled!==false?'checked':''} onchange='setField(\\\"outputs\\\",${i},\\\"enabled\\\",this.checked)' style='width:auto'/> ${t('enabled')}</label></div></div>${type==='relay'?`<div class='row'><div><label>${t('active_level')}</label><select onchange='setField(\\\"outputs\\\",${i},\\\"active_level\\\",Number(this.value))'><option value='1' ${Number(pick(o.active_level,1))===1?'selected':''}>1</option><option value='0' ${Number(pick(o.active_level,1))===0?'selected':''}>0</option></select></div><div><label><input type='checkbox' ${o.default_on?'checked':''} onchange='setField(\\\"outputs\\\",${i},\\\"default_on\\\",this.checked)' style='width:auto'/> ${t('default_on')}</label></div></div>`:''}${type==='pwm'?`<div class='row3'><div><label>${t('freq_hz')}</label><input type='number' value='${esc(pick(o.freq_hz,1000))}' oninput='setField(\\\"outputs\\\",${i},\\\"freq_hz\\\",Number(this.value||0))'/></div><div><label>${t('default_level')}</label><input type='number' min='0' max='100' value='${esc(pick(o.default_level,0))}' oninput='setField(\\\"outputs\\\",${i},\\\"default_level\\\",Number(this.value||0))'/></div><div><label><input type='checkbox' ${o.inverted?'checked':''} onchange='setField(\\\"outputs\\\",${i},\\\"inverted\\\",this.checked)' style='width:auto'/> ${t('inverted')}</label></div></div>`:''}${type==='ws2812'?`<div class='row3'><div><label>${t('pixels')}</label><input type='number' value='${esc(pick(o.pixel_count,1))}' oninput='setField(\\\"outputs\\\",${i},\\\"pixel_count\\\",Number(this.value||1))'/></div><div><label>${t('color_order')}</label><input value='${esc(pick(o.color_order,'GRB'))}' oninput='setField(\\\"outputs\\\",${i},\\\"color_order\\\",this.value)'/></div><div><label><input type='checkbox' ${o.default_power_on?'checked':''} onchange='setField(\\\"outputs\\\",${i},\\\"default_power_on\\\",this.checked)' style='width:auto'/> ${t('default_on')}</label></div></div>`:''}</div>`;}).join('');}"
"function renderIo(){const items=ioEntries();document.getElementById('io').innerHTML=items.length?items.map((entry,row)=>{const o=entry.data;const sec=entry.section;const idx=entry.idx;const isButton=entry.kind==='button';return `<div class='item'><div class='itemhead'><strong>${esc(o.name||o.id||(`${isButton?t('button_name'):t('io_name')} ${row+1}`))}</strong><button class='danger' onclick='removeItem(\\\"${sec}\\\",${idx})'>${t('remove')}</button></div><div class='row3'><div><label>${t('kind')}</label><select onchange='changeIoKind(\\\"${sec}\\\",${idx},this.value)'><option value='input' ${!isButton?'selected':''}>${t('kind_input')}</option><option value='button' ${isButton?'selected':''}>${t('kind_button')}</option></select></div><div><label>${t('id')}</label><input value='${esc(o.id||'')}' oninput='setField(\\\"${sec}\\\",${idx},\\\"id\\\",this.value)'/></div><div><label>${t('name')}</label><input value='${esc(o.name||'')}' oninput='setField(\\\"${sec}\\\",${idx},\\\"name\\\",this.value)'/></div></div><div class='row3'><div><label>${t('gpio')}</label><select onchange='setField(\\\"${sec}\\\",${idx},\\\"gpio\\\",Number(this.value))'>${gpioOptions(pick(o.gpio,0))}</select></div><div><label>${t('pull')}</label><select onchange='setField(\\\"${sec}\\\",${idx},\\\"pull\\\",this.value)'>${enumOptions(PULLS,pick(o.pull,'up'),PULL_LABELS)}</select></div>${isButton?`<div><label>${t('long_press_ms')}</label><input type='number' value='${esc(pick(o.long_press_ms,1000))}' oninput='setField(\\\"${sec}\\\",${idx},\\\"long_press_ms\\\",Number(this.value||1000))'/></div>`:`<div><label>${t('role')}</label><select onchange='setField(\\\"${sec}\\\",${idx},\\\"role\\\",this.value)'>${enumOptions(INPUT_ROLES,pick(o.role,'generic_binary'),INPUT_ROLE_LABELS)}</select></div>`}</div><div class='row'><div><label><input type='checkbox' ${o.inverted?'checked':''} onchange='setField(\\\"${sec}\\\",${idx},\\\"inverted\\\",this.checked)' style='width:auto'/> ${t('inverted')}</label></div><div><label><input type='checkbox' ${o.enabled!==false?'checked':''} onchange='setField(\\\"${sec}\\\",${idx},\\\"enabled\\\",this.checked)' style='width:auto'/> ${t('enabled')}</label></div></div>${isButton?actionEditor(sec,idx,'short',(o.actions||{}).short)+actionEditor(sec,idx,'long',(o.actions||{}).long):''}</div>`;}).join(''):`<div class='muted'>${t('empty_io')}</div>`;}"
"function renderSensors(){document.getElementById('sensors').innerHTML=cfg.sensors.map((o,i)=>{const type=pick(o.type,'ds18b20_bus');return `<div class='item'><div class='itemhead'><strong>${esc(o.name||o.id||(`${t('sensor_name')} ${i+1}`))}</strong><button class='danger' onclick='removeItem(\\\"sensors\\\",${i})'>${t('remove')}</button></div><div class='row'><div><label>${t('id')}</label><input value='${esc(o.id||'')}' oninput='setField(\\\"sensors\\\",${i},\\\"id\\\",this.value)'/></div><div><label>${t('name')}</label><input value='${esc(o.name||'')}' oninput='setField(\\\"sensors\\\",${i},\\\"name\\\",this.value)'/></div></div><div class='row3'><div><label>${t('type')}</label><select onchange='setField(\\\"sensors\\\",${i},\\\"type\\\",this.value)'>${enumOptions(SENSOR_TYPES,type,SENSOR_TYPE_LABELS)}</select></div><div><label>${t('poll_sec')}</label><input type='number' value='${esc(pick(o.poll_interval_sec,30))}' oninput='setField(\\\"sensors\\\",${i},\\\"poll_interval_sec\\\",Number(this.value||30))'/></div><div><label><input type='checkbox' ${o.enabled!==false?'checked':''} onchange='setField(\\\"sensors\\\",${i},\\\"enabled\\\",this.checked)' style='width:auto'/> ${t('enabled')}</label></div></div>${type==='ds18b20_bus'?`<div><label>${t('gpio')}</label><select onchange='setField(\\\"sensors\\\",${i},\\\"gpio\\\",Number(this.value))'>${gpioOptions(pick(o.gpio,0))}</select></div>`:`<div class='row3'><div><label>${t('sda')}</label><select onchange='setField(\\\"sensors\\\",${i},\\\"sda_gpio\\\",Number(this.value))'>${gpioOptions(pick(o.sda_gpio,0))}</select></div><div><label>${t('scl')}</label><select onchange='setField(\\\"sensors\\\",${i},\\\"scl_gpio\\\",Number(this.value))'>${gpioOptions(pick(o.scl_gpio,1))}</select></div><div><label>${t('address')}</label><input value='${esc(pick(o.address,type==='aht20'?56:type==='sht3x'?68:118))}' oninput='setField(\\\"sensors\\\",${i},\\\"address\\\",Number(this.value||0))'/></div></div>`}</div>`;}).join('');}"
"function boardHint(){const key=pick(cfg.device.board_profile,'esp32-c3-supermini');const hint=BOARD_HINTS[key]||BOARD_HINTS['esp32-c3-supermini'];return hint[lang]||hint.en||'';}"
"function renderMeta(){document.getElementById('device_name').value=pick(cfg.device.name,'');document.getElementById('hostname').value=pick(cfg.connectivity.hostname,'esp32-c3');document.getElementById('ap_ssid').value=pick(cfg.connectivity.ap.ssid,'ESP32-SETUP');document.getElementById('ap_pass').value=pick(cfg.connectivity.ap.pass,'');document.getElementById('sta_ssid').value=pick(cfg.connectivity.sta.ssid,'');document.getElementById('sta_pass').value=pick(cfg.connectivity.sta.pass,'');document.getElementById('mqtt_host').value=pick(cfg.connectivity.mqtt.host,'');document.getElementById('mqtt_port').value=pick(cfg.connectivity.mqtt.port,1883);document.getElementById('mqtt_user').value=pick(cfg.connectivity.mqtt.user,'');document.getElementById('mqtt_pass').value=pick(cfg.connectivity.mqtt.pass,'');document.getElementById('mqtt_topic_prefix').value=pick(cfg.connectivity.mqtt.topic_prefix,'');document.getElementById('mqtt_client_id').value=pick(cfg.connectivity.mqtt.client_id,'');document.getElementById('mqtt_discovery_prefix').value=pick(cfg.connectivity.mqtt.discovery_prefix,'homeassistant');document.getElementById('mqtt_enable').checked=cfg.connectivity.mqtt.enable===true;document.getElementById('mqtt_discovery').checked=cfg.connectivity.mqtt.discovery!==false;document.getElementById('mqtt_retain').checked=cfg.connectivity.mqtt.retain!==false;document.getElementById('board_profile').innerHTML=boardOptions(pick(cfg.device.board_profile,'esp32-c3-supermini'));document.getElementById('board_profile').value=pick(cfg.device.board_profile,'esp32-c3-supermini');document.getElementById('board_hint').textContent=boardHint();}"
"function updateMetaFromInputs(){cfg.device.name=document.getElementById('device_name').value.trim();cfg.connectivity.hostname=document.getElementById('hostname').value.trim();cfg.connectivity.ap.ssid=document.getElementById('ap_ssid').value.trim();cfg.connectivity.ap.pass=document.getElementById('ap_pass').value;cfg.connectivity.sta.ssid=document.getElementById('sta_ssid').value.trim();cfg.connectivity.sta.pass=document.getElementById('sta_pass').value;cfg.connectivity.mqtt.enable=document.getElementById('mqtt_enable').checked;cfg.connectivity.mqtt.host=document.getElementById('mqtt_host').value.trim();cfg.connectivity.mqtt.port=Number(document.getElementById('mqtt_port').value||1883);cfg.connectivity.mqtt.user=document.getElementById('mqtt_user').value.trim();cfg.connectivity.mqtt.pass=document.getElementById('mqtt_pass').value;cfg.connectivity.mqtt.topic_prefix=document.getElementById('mqtt_topic_prefix').value.trim();cfg.connectivity.mqtt.client_id=document.getElementById('mqtt_client_id').value.trim();cfg.connectivity.mqtt.discovery_prefix=document.getElementById('mqtt_discovery_prefix').value.trim();cfg.connectivity.mqtt.discovery=document.getElementById('mqtt_discovery').checked;cfg.connectivity.mqtt.retain=document.getElementById('mqtt_retain').checked;cfg.device.board_profile=document.getElementById('board_profile').value;}"
"function validateGpios(){const used={};const errors=[];const touch=(label,g)=>{if(g===undefined||g===null||g==='')return;const key=String(g);used[key]=used[key]||[];used[key].push(label);};cfg.outputs.forEach(o=>touch(`${t('output_name')} ${o.id||o.name||'?'}`,o.gpio));cfg.inputs.forEach(o=>touch(`${t('io_name')} ${o.id||o.name||'?'}`,o.gpio));cfg.buttons.forEach(o=>touch(`${t('button_name')} ${o.id||o.name||'?'}`,o.gpio));cfg.sensors.forEach(o=>{if(o.type==='ds18b20_bus'){touch(`${t('sensor_name')} ${o.id||o.name||'?'}`,o.gpio);}else{touch('i2c_sda',o.sda_gpio);touch('i2c_scl',o.scl_gpio);}});Object.entries(used).forEach(([gpio,list])=>{if(list.length>1&&!(list.every(v=>v==='i2c_sda')||list.every(v=>v==='i2c_scl')))errors.push(`GPIO${gpio}: ${list.join(', ')}`);});document.getElementById('gpio_summary').innerHTML=errors.length?`<span class='err'>${t('conflicts')}:</span><br>${errors.map(esc).join('<br>')}`:`<span class='ok'>${t('no_gpio_conflicts')}</span>`;}"
"function applyI18n(){document.documentElement.lang=(lang==='ru'?'ru':'en');document.title=t('title');document.getElementById('lang_select').value=lang;document.getElementById('page_title').textContent=t('title');document.getElementById('page_subtitle').textContent=t('subtitle');document.getElementById('btn_scan_wifi').textContent=t('scan_wifi');document.getElementById('btn_save_apply').textContent=t('save_apply');document.getElementById('btn_apply_only').textContent=t('apply_only');document.getElementById('btn_factory_reset').textContent=t('factory_reset');document.getElementById('connectivity_title').textContent=t('connectivity');document.getElementById('lbl_device_name').textContent=t('device_name');document.getElementById('lbl_hostname').textContent=t('hostname');document.getElementById('lbl_ap_ssid').textContent=t('ap_ssid');document.getElementById('lbl_ap_pass').textContent=t('ap_pass');document.getElementById('lbl_wifi_scan').textContent=t('wifi_scan');document.getElementById('lbl_sta_ssid').textContent=t('sta_ssid');document.getElementById('lbl_sta_pass').textContent=t('sta_pass');document.getElementById('lbl_mqtt_host').textContent=t('mqtt_host');document.getElementById('lbl_mqtt_port').textContent=t('mqtt_port');document.getElementById('lbl_mqtt_user').textContent=t('mqtt_user');document.getElementById('lbl_mqtt_pass').textContent=t('mqtt_pass');document.getElementById('lbl_topic_prefix').textContent=t('topic_prefix');document.getElementById('lbl_client_id').textContent=t('client_id');document.getElementById('lbl_discovery_prefix').textContent=t('discovery_prefix');document.getElementById('lbl_board_profile').textContent=t('board_profile');document.getElementById('lbl_mqtt_enable').textContent=t('mqtt_enabled');document.getElementById('lbl_mqtt_discovery').textContent=t('ha_discovery');document.getElementById('lbl_mqtt_retain').textContent=t('retain');document.getElementById('gpio_policy_title').textContent=t('gpio_policy');document.getElementById('allowed_hint').textContent='allowed: 0 1 3 4 5 6 7 10';document.getElementById('reset_hint').textContent='reset: 9';document.getElementById('usb_hint').textContent='USB: 18 19';document.getElementById('uart_hint').textContent='UART: 20 21';document.getElementById('lbl_runtime_status').textContent=t('runtime_status');document.getElementById('outputs_title').textContent=t('outputs');document.getElementById('btn_add_output').textContent=t('add_output');document.getElementById('io_title').textContent=t('io_title');document.getElementById('btn_add_io').textContent=t('add_io');document.getElementById('sensors_title').textContent=t('sensors');document.getElementById('btn_add_sensor').textContent=t('add_sensor');document.getElementById('raw_title').textContent=t('raw_title');document.getElementById('raw_subtitle').textContent=t('raw_subtitle');}"
"function render(){ensure();applyI18n();renderMeta();renderOutputs();renderIo();renderSensors();refreshRaw();validateGpios();}"
"function setLang(value){lang=(value==='en'?'en':'ru');localStorage.setItem('ui_lang',lang);render();loadStatus();}"
"function addOutput(){cfg.outputs.push({id:`out${cfg.outputs.length+1}`,name:`${t('output_name')} ${cfg.outputs.length+1}`,type:'relay',enabled:true,gpio:0,active_level:1,default_on:false});render();}"
"function addIo(){cfg.inputs.push({id:`in${cfg.inputs.length+1}`,name:`${t('io_name')} ${cfg.inputs.length+1}`,type:'digital',enabled:true,gpio:0,pull:'up',inverted:false,role:'generic_binary'});render();}"
"function addSensor(){cfg.sensors.push({id:`sensor${cfg.sensors.length+1}`,name:`${t('sensor_name')} ${cfg.sensors.length+1}`,type:'ds18b20_bus',enabled:true,gpio:0,poll_interval_sec:30});render();}"
"async function loadStatus(){const[rt,mods]=await Promise.all([fetch('/api/runtime').then(r=>r.json()),fetch('/api/modules').then(r=>r.json())]);document.getElementById('runtime').textContent=`${t('mode')}: ${rt.mode||'?'} | ${t('mqtt_state')}: ${rt.mqtt_connected?t('connected'):t('offline')} | ${t('ap_state')}: ${rt.ap_ssid||'-'}`;document.getElementById('runtime_status').textContent=JSON.stringify(mods,null,2);}"
"async function loadCfg(){cfg=await fetch('/api/config').then(r=>r.json());ensure();render();await loadStatus();if(!cfg.connectivity.sta.ssid){await scanWifi(true);}}"
"async function scanWifi(initial){try{const r=await fetch('/api/wifi/scan');if(!r.ok)throw new Error(await r.text()||('HTTP '+r.status));const j=await r.json();const nets=j.networks||[];const sel=document.getElementById('wifi_scan_list');sel.innerHTML=`<option value=''>${esc(t('select_network'))}</option>`+nets.map(n=>`<option value='${esc(n.ssid)}'>${esc(n.ssid)} (${n.rssi} dBm)</option>`).join('');sel.onchange=()=>{if(sel.value)document.getElementById('sta_ssid').value=sel.value;};setMsg(fmt(j.cached?t('found_networks_cached'):t('found_networks'),{count:nets.length}),true);}catch(e){if(!initial)setMsg(String(e),false);}}"
"async function saveOnly(){updateMetaFromInputs();const r=await fetch('/api/config',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(cfg)});const text=await r.text();if(!r.ok)throw new Error(text||('HTTP '+r.status));setMsg(t('msg_saved'),true);}"
"async function saveAndApply(){try{await saveOnly();const r=await fetch('/api/apply',{method:'POST'});if(!r.ok)throw new Error(await r.text());setMsg(t('msg_saved_apply'),true);setTimeout(loadStatus,900);}catch(e){setMsg(String(e),false);}}"
"async function applyOnly(){try{const r=await fetch('/api/apply',{method:'POST'});if(!r.ok)throw new Error(await r.text());setMsg(t('msg_apply'),true);setTimeout(loadStatus,900);}catch(e){setMsg(String(e),false);}}"
"async function factoryReset(){try{if(!confirm(t('confirm_reset')))return;const r=await fetch('/api/factory-reset',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({confirm:'ERASE'})});if(!r.ok)throw new Error(await r.text());setMsg(t('msg_reset'),true);}catch(e){setMsg(String(e),false);}}"
"window.setField=setField;window.setNested=setNested;window.removeItem=removeItem;window.addOutput=addOutput;window.addIo=addIo;window.addSensor=addSensor;window.scanWifi=scanWifi;window.saveAndApply=saveAndApply;window.applyOnly=applyOnly;window.factoryReset=factoryReset;window.setLang=setLang;window.changeIoKind=changeIoKind;"
"loadCfg();"
"</script></div></body></html>";
